import requests, json, time
from concurrent.futures import ThreadPoolExecutor, as_completed

CORTEX_URL = "http://192.168.1.199:9001"
HEADERS = {
    "Authorization": "Bearer 3Er5nTalewwwps1hVOA01Gkt1/YDSjUI",
    "Content-Type": "application/json",
}
ANALYZERS = {
    "Abuse_Finder_3_0":         "199851cd04ee495c5b2e839423c968aa",
    "VirusTotal_GetReport_3_1": "d23c4487797a082b0f32108fe80dd5ca",
    "AbuseIPDB_2_0":            "23c4c66e7a75db8384a4276148922986",
    "URLhaus_2_0":              "cefcda5343e9a92a0c494bc049e20541",
    "OTXQuery_2_0":             "cb8d9f32eefc897fc4e3144352c20ddd",
    "MISP_2_1":                 "2f101f2a7536b374a2b384682eabcaeb",
}
OBSERVABLE = "$alert_receiver.all_fields.data.srcip"
DATA_TYPE  = "ip"

# ── FREE enrichment (no API key needed) ───────────────────────────────────
def get_geoip(ip):
    try:
        r = requests.get(
            f"http://ip-api.com/json/{ip}?fields=status,country,countryCode,region,regionName,city,lat,lon,isp,org,as,query",
            timeout=10)
        data = r.json()
        if data.get("status") == "success":
            return {"GeoIP_ip-api": data}
        return {"GeoIP_ip-api": {"error": data.get("message", "lookup failed")}}
    except Exception as e:
        return {"GeoIP_ip-api": {"error": str(e)}}

def get_shodan_internetdb(ip):
    try:
        r = requests.get(f"https://internetdb.shodan.io/{ip}", timeout=10)
        if r.status_code == 200:
            return {"Shodan_InternetDB": r.json()}
        elif r.status_code == 404:
            return {"Shodan_InternetDB": {"info": "No data found for this IP"}}
        return {"Shodan_InternetDB": {"error": f"HTTP {r.status_code}"}}
    except Exception as e:
        return {"Shodan_InternetDB": {"error": str(e)}}

# ── PHASE 1: submit all Cortex jobs ────────────────────────────────────────
def submit_job(name, aid):
    try:
        r = requests.post(f"{CORTEX_URL}/api/analyzer/{aid}/run", headers=HEADERS,
            json={"data": OBSERVABLE, "dataType": DATA_TYPE, "tlp": 2}, timeout=10)
        r.raise_for_status()
        jid = r.json().get("id") or r.json().get("_id")
        return name, jid
    except Exception as e:
        return name, None

job_ids = {}
with ThreadPoolExecutor(max_workers=8) as ex:
    for name, jid in ex.map(lambda kv: submit_job(*kv), ANALYZERS.items()):
        job_ids[name] = jid

# ── PHASE 2: flat wait ─────────────────────────────────────────────────────
time.sleep(95)

# ── PHASE 3: collect everything in parallel ────────────────────────────────
def fetch_result(name, jid):
    if not jid:
        return name, {"error": "failed to submit job"}
    try:
        s = requests.get(f"{CORTEX_URL}/api/job/{jid}", headers=HEADERS, timeout=10).json()
        status = s.get("status")
        if status == "Success":
            rep = requests.get(f"{CORTEX_URL}/api/job/{jid}/report", headers=HEADERS, timeout=10)
            return name, rep.json()
        elif status == "Failure":
            return name, {"error": "job failed", "status": status}
        else:
            return name, {"error": f"still running after 70s — status: {status}"}
    except Exception as e:
        return name, {"error": str(e)}

results = {}
with ThreadPoolExecutor(max_workers=8) as ex:
    cortex_futures = {ex.submit(fetch_result, n, jid): n for n, jid in job_ids.items()}
    geoip_future   = ex.submit(get_geoip, OBSERVABLE)
    shodan_future  = ex.submit(get_shodan_internetdb, OBSERVABLE)

    for f in as_completed(cortex_futures):
        n, result = f.result()
        results[n] = result

    results.update(geoip_future.result())
    results.update(shodan_future.result())

print(json.dumps({"observable": OBSERVABLE, "results": results}, indent=2))
